import{_ as a,c as l,g as e,o as n}from"./chunks/framework.CCxIPCIe.js";const m=JSON.parse('{"title":"四二一","description":"","frontmatter":{"title":"四二一","date":"2025-09-09T12:47:13.501Z","length":"1894字","time":"7分钟","aside":false,"hash":-721858085},"headers":[],"relativePath":"idea/421.md","filePath":"idea/421.md"}'),s={name:"idea/421.md"};function r(o,t,p,d,i,c){return n(),l("div",null,t[0]||(t[0]=[e("p",null,"在黑格尔看来，自我意识追求得到另一个自我意识的承认。简而言之，作为自我意识存在的人，需要另一个人的承认，而这种承认是无法忽视对象的存在，不得不承认自己的生活必须经过对象的介入才能实现，即对对象的需要。 为什么爱情是卸除一个人存在压力最简捷的方式？因为爱情是最简单的承认关系，是两个自我意识相互承认，二者彼此需要，也暴露彼此的残缺。 这种残缺并非身体或是人格的残缺，而是符号意义上的残缺，即人的存在必须依赖于他者的承认而得以维系，这个符号意义上的缺口必须由他者的承认来填补。而爱情是用于填补这种缺口的最简单的社会形式。也是在这意义上，我们说爱情中的双方是互补的，它未必是性格上的互补，但一定是符号意义上的互补。 这种补足会给人一种错觉，即得到了对象就补足了全部——这就是私奔性，即当我得到了对象的承认后，我便似乎不再需要其他任何人的承认了。无论其他人怎样需要我，我都可以置之不理，何况他们可能触发我的存在危机，索性远远躲开。 这种对对象的错觉，哪怕只是对尚未出现而存在于自己想象中的对象的错觉，本质上来自于自恋：我如此重要，因而我值得被全部补足，我值得拥有一个完美的爱人。但这种想象是荒谬的，一个完美的人就不会再需要外部，因此不会爱上你。所以这里所谓的完美的爱人，其实指的是我值得拥有一个恰好能满足我所有需求的人，以使我成为一个完美的人；又或是更加自恋的，我已经是一个完美的人，我值得拥有一个随时能欣赏我是完美的人。 古往今来大部分的私奔故事，总以殉情而终，只有这样才能维护爱情的美好。这不单是庸俗的套路，说什么热恋期最美好，而只有死亡才能永远定格，它其实揭示的是，爱情最初总是以一种解放者的姿态降临到一个人的存在危机中，仿佛它将一劳永逸的纾解这种危机，但这是不可能的，人生并非是一场寻找爱情的游戏，遇到那个人便完结了，没有危机了。爱情只是一种偶然，它出现与否并不影响存在危机随时浮现，人只有处于不同的社会关系中，得到由那种社会关系带来的被需要的满足，从而暂时的纾解这种存在危机。所以相爱的故事后面往往嫌隙渐生，双方才意识到彼此并非“真正需要”——爱情若要得以延续就必须与这种“真正”、“纯粹”、“全部”拉开距离，也即爱情必须以对爱情保持怀疑并依然认其为爱情的形式才能存在。（红楼梦有钗黛一体说，那么为什么贾宝玉明明和薛宝钗结婚，却依旧怀念林黛玉而出家？林黛玉不适合进入婚姻，与其说死去的是林黛玉，不如说林黛玉的人格在结婚那一刻在钗黛身上死去，而只有这样，宝黛爱情才有永存的可能，因为死亡所以永恒，也因为永恒所以需要死亡，也只有这样宝钗才会以进入婚姻的形式，或者以进入婚姻的那种可能性被甩出来——这是一幕双重悲剧，黛玉是宝钗婚姻的祭品，而宝钗则是宝黛爱情的祭品）于是人们意识到除非存在本身被消解，否则危机将一直延续。因此生命的意义就是回答为什么我还没有去死，去不断的寻求他者的承认，从他者的承认中获得自己的意义。",-1),e("p",null,"“情绪价值”反映了对这种承认的需要——我不仅需要物质，还需要精神上的重视。所谓重视，就是需要——人只会重视他需要的。因此对情绪价值的需要就是对被需要的需要，我需要你告诉我：“我需要你”。无论是礼物还是情话，都最终被折合成为这份情绪价值而抵达。",-1),e("p",null,"但问题在于，我需要你是根本抽象的东西，我无法说出“我需要你”这个元话语，我只能用我需要你怎样怎样（做一件具体的事）来表达我的需要。",-1),e("p",null,"被惯坏的对象并不会满足对方对它的需要，毕竟那意味着“低人一等”，既然没有满足对方的需要，又如何体现自己被需要呢？只能通过种种礼物或情话，即通过自己获得的奖赏或表扬来暗示自己的付出（否则不会凭空得到奖赏），从而迂回的满足自己被需要的需要。于是吊诡的一幕出现了，一个人不是通过付出，而是通过索取来实现它的被需要的需要，事实上它反而是那个最需要别人的人，需要别人用礼物和情话不断的供奉它的需要的人。它无法心安理得的索取，因为它知道明明自己没有什么付出，却能获得这些“回报”，因而它只能把自己的索取包装成“一个付出者的理直气壮”，它理直气壮的缘由在于它需要压抑这种不安。",-1),e("p",null,"现在有人说对象“有义务提供情绪价值”，这就取消了主体本应付出的努力——他把主体所应争取的他者的承认，变成他者应该向他提供的一种无条件的义务。也就是说，他把主体被他者需要的需要，变成了他者应当无条件的需要主体。",-1),e("p",null,"然而承认的辩证法在此运行了。自我意识所收到的承认必须由另一个自我意识所发出，而这就意味着另一个自我意识绝不是无条件的，否则它就称不上意识，自我意识必然是能动的，绝不听命于谁，只能是它自己。因此，那种无条件的承认就贬值了，俗称为舔狗。没有人会认真对待舔狗的承认。人是慕强的，因为来自强者的承认是更贵的，只有战胜强者才能得到强者的承认。",-1),e("p",null,"因此，“无条件的提供情绪价值”实际上把自我意识贬低到奴隶的层面，好比奴隶无偿的为主人提供劳役和赋税，感情双方的关系被降低为封建经济关系。即便去掉“无条件性”，它至多被提升到资本主义经济关系。这反映出思维的贫乏，在以经济为唯一目的的社会中生活的人们对社会关系的见解只能把它理解为一种经济关系。",-1)]))}const _=a(s,[["render",r]]);export{m as __pageData,_ as default};
